import numpy as np
import pandas as pd


EQ_VAS_CONCEPT_ID = 42537274


def extract_patient_ref(value):
    """Extract raw patient reference string from a person_id value."""
    if isinstance(value, dict):
        return value.get("reference") or value.get("id") or str(value)
    if isinstance(value, list):
        value = value[0] if value else None
    return str(value) if value is not None else None


def flatten_measurements(df):
    """
    Flatten a DataFrame where some columns contain lists.

    Behavior:
      - Expand list-valued columns into individual rows.
      - Assign sequential person_id starting from 1, stable per unique
        patient reference across the entire batch.
      - Skip rows where measurement_concept_id is None or NaN.
      - Overwrite measurement_source_value with value_source_value (QR ID)
        and clear value_source_value.
      - Set value_as_number only for eq_vas — skip string values.
      - Assign unique sequential measurement_id.
    """
    all_rows = []

    # ── Build patient registry: raw reference → sequential integer ────────
    patient_registry = {}

    for _, row in df.iterrows():
        person_val = row.get("person_id", None)
        if isinstance(person_val, list):
            person_val = person_val[0] if person_val else None
        raw_ref = extract_patient_ref(person_val)
        if raw_ref and raw_ref not in patient_registry:
            patient_registry[raw_ref] = len(patient_registry) + 1

    print(f"[patient registry] {len(patient_registry)} unique patients: {patient_registry}")

    # ── Flatten rows ──────────────────────────────────────────────────────
    for idx, row in df.iterrows():
        print(f"[incoming row {idx}] {row.to_dict()}")

        # Capture value_as_number — skip strings (e.g. 'slight-problems')
        row_vas = row.get("value_as_number", None)
        if isinstance(row_vas, list):
            row_vas = next((v for v in row_vas if not isinstance(v, str)), None)
        elif isinstance(row_vas, str):
            row_vas = None

        # Determine maximum list length in this row
        max_len = max(
            (len(val) for val in row if isinstance(val, list)),
            default=1
        )

        for i in range(max_len):
            entry = {}
            for col, val in row.items():
                if col in ("measurement_id", "person_id"):
                    continue
                if isinstance(val, list):
                    entry[col] = val[i] if i < len(val) else None
                else:
                    entry[col] = val

            # ── Skip rows with no measurement_concept_id ──────────────────
            meas = entry.get("measurement_concept_id", None)
            if isinstance(meas, float) and np.isnan(meas):
                meas = None
            if isinstance(meas, (float, np.floating)):
                try:
                    meas = int(meas)
                except Exception:
                    meas = None
            if meas is None:
                continue
            entry["measurement_concept_id"] = int(meas)

            # ── Assign sequential person_id ───────────────────────────────
            person_val = row.get("person_id", None)
            if isinstance(person_val, list):
                person_val = person_val[i] if i < len(person_val) else person_val[0] if person_val else None
            raw_ref = extract_patient_ref(person_val)
            entry["person_id"] = patient_registry.get(raw_ref, 1)

            # ── value_as_number: only for eq_vas ──────────────────────────
            entry["value_as_number"] = (
                row_vas if meas == EQ_VAS_CONCEPT_ID else None
            )

            # ── Swap: measurement_source_value ← QR ID (value_source_value)
            entry["measurement_source_value"] = entry.get("value_source_value", None)
            entry["value_source_value"] = None

            all_rows.append(entry)

    result_df = pd.DataFrame(all_rows)

    if result_df.empty:
        return result_df

    # ── Assign unique sequential measurement_id ───────────────────────────
    result_df["measurement_id"] = range(1, len(result_df) + 1)
    cols = ["measurement_id", "person_id"] + [
        c for c in result_df.columns if c not in ("measurement_id", "person_id")
    ]
    result_df = result_df[cols]

    return result_df.reset_index(drop=True)


def exec(myinput):
    data = myinput.get("transform_fhir_to_omop").result
    print("All incoming rows:")
    for i, row in data.iterrows():
        print(f"Row {i}: {row.to_dict()}")
    df = flatten_measurements(data)
    print("Flattened output:")
    print(df.to_string())
    return df
